const item = $input.first();
const body = item.json?.body || {};
const binary = item.binary || {};
const defaultKbId = '00000000-0000-4000-8000-000000000001';
const uuid = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
const requested = String(body.action || (binary.data || binary.file ? 'ingest' : (body.query || body.message ? 'query' : ''))).trim().toLowerCase();
const action = requested === 'reprocess' ? 'reset' : requested;
const kbId = String(body.kbId || defaultKbId).trim();
const query = String(body.query || body.message || '').trim();
const documentId = String(body.documentId || '').trim();
const confirm = String(body.confirm || '').trim();
const force = body.force === true || String(body.force || '').toLowerCase() === 'true';
const reprocess = requested === 'reprocess';
const topK = Math.max(1, Math.min(12, Number(body.topK || 6) || 6));
let error = '';
let statusCode = 400;
const binaryInputName = binary.data ? 'data' : 'file';
let file = binary.data || binary.file;
let sourceSize = Number(file?.fileSize || 0);
if (action === 'ingest') {
  if (!file) error = 'action=ingest requires a multipart file in binary field "data"';
  if (!error && !uuid.test(kbId)) error = 'kbId must be a UUID';
  if (!error && !sourceSize) {
    const buffer = await this.helpers.getBinaryDataBuffer(0, binaryInputName);
    sourceSize = buffer.length;
  }
  if (!error && sourceSize <= 0) error = 'Uploaded file is empty';
  if (!error && sourceSize > 26214400) { error = 'Uploaded file exceeds 25 MiB'; statusCode = 413; }
} else if (action === 'query') {
  if (!query) error = 'action=query requires query or message';
  if (!error && !uuid.test(kbId)) error = 'kbId must be a UUID';
} else if (action === 'reset') {
  if (confirm !== 'RESET') error = 'reset and reprocess require confirm=RESET';
  if (!error && documentId && !uuid.test(documentId)) error = 'documentId must be a UUID';
  if (!error && !documentId && !uuid.test(kbId)) error = 'kbId must be a UUID';
  if (!error && reprocess && !documentId) error = 'reprocess requires documentId';
} else {
  error = 'action must be ingest, query, reset, or reprocess';
}
const filename = String(file?.fileName || body.filename || 'upload.bin').replace(/[\\/]/g, '_');
const extension = (filename.includes('.') ? filename.split('.').pop() : 'bin').toLowerCase();
const mimeType = String(file?.mimeType || body.mimeType || 'application/octet-stream');
return [{
  json: { action: error ? 'invalid' : action, requestedAction: requested, requestSource: 'webhook', kbId, query, documentId, confirm, force, reprocess, topK, filename, extension, mimeType, sourceSize, error, statusCode },
  binary: file ? {...binary, data: file} : binary
}];

const item = $input.first();
const binary = item.binary || {};
if (!binary.data) throw new Error('Watched path did not produce binary data');
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
if (buffer.length > 26214400) throw new Error('Watched file exceeds 25 MiB');
const rawPath = String(binary.data.fileName || 'watched.bin');
const filename = String(binary.data.fileName || rawPath.split(/[\\/]/).pop() || 'watched.bin').replace(/[\\/]/g, '_');
const extension = (filename.includes('.') ? filename.split('.').pop() : 'bin').toLowerCase();
return [{
  json: {
    action: 'ingest',
    requestedAction: 'ingest',
    requestSource: 'folder',
    kbId: '00000000-0000-4000-8000-000000000001',
    force: true,
    reprocess: false,
    filename,
    extension,
    mimeType: binary.data.mimeType || 'application/octet-stream',
    sourceSize: buffer.length
  },
  binary
}];

