WITH updated AS (
  UPDATE rag_documents
  SET status = 'processing', processing_attempt = processing_attempt + 1, error_code = NULL, error_message = NULL, error_details = NULL, updated_at = now()
  WHERE id = $1::uuid AND status IN ('pending', 'failed')
  RETURNING id
)
INSERT INTO rag_document_events(document_id, status, stage, details)
SELECT id, 'processing', 'orchestrator', '{}'::jsonb FROM updated;
WITH selected AS (
 SELECT id, kb_id, source_key, source_sha256, filename, mime_type, status FROM rag_documents WHERE id = $1::uuid
)
SELECT id::text AS "documentId", kb_id::text AS "kbId", source_key AS "sourceKey", source_sha256 AS "sourceSha256", filename AS filename, mime_type AS "mimeType", status, (status = 'processing') AS "shouldProcess", $2::text AS "requestSource" FROM selected;

UPDATE rag_documents SET status = 'extracting', updated_at = now() WHERE id = $1::uuid;
INSERT INTO rag_document_events(document_id, status, stage, details) VALUES ($1::uuid, 'extracting', 'docling', jsonb_build_object('sourceKey', $2::text));
SELECT $1::text AS "documentId";

parameters.jsCode:
const contract = $('Claim Document').first().json;
const input = $input.first();
const binary = input.binary || {};
const entries = [];
for (const key of Object.keys(binary)) {
  const meta = binary[key];
  const buffer = await this.helpers.getBinaryDataBuffer(0, key);
  entries.push({ key, meta, buffer });
}
const jsonEntry = entries.find(e => (e.meta.fileName || '').toLowerCase().endsWith('.json'));
const mdEntry = entries.find(e => (e.meta.fileName || '').toLowerCase().endsWith('.md'));
if (!jsonEntry || !mdEntry) throw new Error('Docling ZIP must contain both JSON and Markdown outputs');

const doc = JSON.parse(jsonEntry.buffer.toString('utf8'));
let markdown = mdEntry.buffer.toString('utf8');
const imageEntries = entries.filter(e => /\.(png|jpe?g|webp|gif|tiff?|bmp)$/i.test(e.meta.fileName || ''));
markdown = markdown.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, (_, alt, ref) => {
  const base = String(ref).replace(/\\/g, '/').split('/').pop();
  return '![' + alt + '](images/' + base + ')';
});

const byRef = new Map();
for (const collection of ['groups','texts','tables','pictures','key_value_items','form_items']) {
  for (const item of (doc[collection] || [])) {
    if (item && item.self_ref) byRef.set(item.self_ref, item);
  }
}
const pageOf = item => {
  const p = item && Array.isArray(item.prov) ? item.prov[0] : null;
  return Number.isInteger(p?.page_no) ? p.page_no : null;
};
const esc = value => String(value ?? '').replace(/\|/g, '\\|').replace(/\r?\n/g, ' ');
const tableMarkdown = table => {
  const grid = table?.data?.grid;
  if (!Array.isArray(grid) || grid.length === 0) return '[Table]';
  const rows = grid.map(row => row.map(cell => esc(cell?.text ?? cell)).join(' | '));
  const width = Math.max(...grid.map(row => row.length), 1);
  return '| ' + rows[0] + ' |\n| ' + Array(width).fill('---').join(' | ') + ' |\n' +
    rows.slice(1).map(r => '| ' + r + ' |').join('\n');
};
const blocks = [];
let headings = [];
const pushBlock = (item, contentType, text) => {
  const clean = String(text || '').trim();
  if (!clean) return;
  const page = pageOf(item);
  blocks.push({ text: clean, heading_path: [...headings], page_start: page, page_end: page, content_type: contentType });
};
const visit = refOrItem => {
  const item = typeof refOrItem === 'string' ? byRef.get(refOrItem) : byRef.get(refOrItem?.$ref) || refOrItem;
  if (!item) return;
  const label = item.label || '';
  if (label === 'title' || label === 'section_header') {
    const level = Math.max(1, Number(item.level || (label === 'title' ? 1 : headings.length + 1)));
    headings = headings.slice(0, level - 1);
    headings[level - 1] = String(item.text || '').trim();
    pushBlock(item, 'heading', item.text);
    return;
  }
  if (item.data?.grid) pushBlock(item, 'table', tableMarkdown(item));
  else if (label === 'picture' || item.self_ref?.startsWith('#/pictures/')) {
    const caption = item.caption_text || item.text || (item.captions || []).map(c => c.text || '').filter(Boolean).join(' ');
    pushBlock(item, 'image', caption ? '[Image] ' + caption : '[Image]');
  } else if (item.text) pushBlock(item, label || 'text', item.text);
  for (const child of (item.children || [])) visit(child);
};
for (const child of (doc.body?.children || [])) visit(child);

if (blocks.length === 0 && markdown.trim()) {
  blocks.push({text: markdown.trim(), heading_path: [], page_start: null, page_end: null, content_type: 'markdown'});
}
const MAX = 1200;
const OVERLAP = 150;
const chunks = [];
const stableUuid = seed => {
  const words = [2166136261, 2246822519, 3266489917, 668265263];
  for (let w = 0; w < words.length; w++) {
    let h = words[w] >>> 0;
    for (let i = 0; i < seed.length; i++) {
      h ^= seed.charCodeAt(i) + w * 31;
      h = Math.imul(h, 16777619 + w * 2) >>> 0;
    }
    words[w] = h;
  }
  let hex = words.map(v => v.toString(16).padStart(8, '0')).join('');
  hex = hex.slice(0, 12) + '5' + hex.slice(13, 16) + ((parseInt(hex[16],16)&3)|8).toString(16) + hex.slice(17);
  return hex.slice(0,8)+'-'+hex.slice(8,12)+'-'+hex.slice(12,16)+'-'+hex.slice(16,20)+'-'+hex.slice(20,32);
};
let current = null;
const emit = () => {
  if (!current || !current.text.trim()) return;
  const index = chunks.length;
  chunks.push({
    id: stableUuid(contract.documentId + ':' + index),
    chunk_id: contract.documentId + ':' + String(index).padStart(6, '0'),
    document_id: contract.documentId,
    kb_id: contract.kbId,
    chunk_index: index,
    text: current.text.trim(),
    heading_path: current.heading_path,
    page_start: current.page_start,
    page_end: current.page_end,
    content_type: current.content_type,
    source_key: contract.sourceKey,
    source_sha256: contract.sourceSha256,
    filename: contract.filename
  });
};
for (const block of blocks) {
  const sameSection = current && JSON.stringify(current.heading_path) === JSON.stringify(block.heading_path) && current.content_type === block.content_type;
  if (!sameSection || (current.text.length + block.text.length + 2 > MAX)) {
    if (current) emit();
    const carry = sameSection && current ? current.text.slice(-OVERLAP) : '';
    current = {...block, text: carry ? carry + '\n\n' + block.text : block.text};
  } else {
    current.text += '\n\n' + block.text;
    if (block.page_start != null) {
      current.page_start = current.page_start == null ? block.page_start : Math.min(current.page_start, block.page_start);
      current.page_end = current.page_end == null ? block.page_end : Math.max(current.page_end, block.page_end);
    }
  }
}
emit();
if (chunks.length === 0) throw new Error('Docling produced no indexable content');

const prefix = 'documents/' + contract.kbId + '/' + contract.documentId + '/';
const manifest = {
  schemaVersion: 1,
  documentId: contract.documentId,
  kbId: contract.kbId,
  source: { key: contract.sourceKey, filename: contract.filename, sha256: contract.sourceSha256, mimeType: contract.mimeType },
  artifacts: {
    json: prefix + 'extracted/document.json',
    markdown: prefix + 'extracted/document.md',
    manifest: prefix + 'extracted/manifest.json',
    images: imageEntries.map(e => prefix + 'extracted/images/' + (e.meta.fileName || e.key).replace(/^.*[\\/]/,'')),
    chunks: prefix + 'chunks/chunks.json'
  },
  chunkCount: chunks.length,
  createdAt: new Date().toISOString()
};
const makeItem = async (objectKey, kind, buffer, fileName, mimeType, extra={}) => ({
  json: { documentId: contract.documentId, kbId: contract.kbId, objectKey, kind, ...extra },
  binary: { data: await this.helpers.prepareBinaryData(buffer, fileName, mimeType) }
});
const output = [];
output.push(await makeItem(prefix+'extracted/document.json','docling_json',Buffer.from(JSON.stringify(doc,null,2)),'document.json','application/json'));
output.push(await makeItem(prefix+'extracted/document.md','markdown',Buffer.from(markdown),'document.md','text/markdown'));
for (const image of imageEntries) {
  const name = (image.meta.fileName || image.key).replace(/^.*[\\/]/,'');
  output.push(await makeItem(prefix+'extracted/images/'+name,'image',image.buffer,name,image.meta.mimeType || 'application/octet-stream'));
}
output.push(await makeItem(prefix+'extracted/manifest.json','manifest',Buffer.from(JSON.stringify(manifest,null,2)),'manifest.json','application/json'));
output.push(await makeItem(prefix+'chunks/chunks.json','chunks',Buffer.from(JSON.stringify(chunks,null,2)),'chunks.json','application/json',{chunks,chunkCount:chunks.length,manifest}));
return output;

const uploaded = $input.all();

const source = $('Build Artifacts and Chunks').all().find(i => i.json.kind === 'chunks');
if (!source) throw new Error('chunks.json artifact was not produced');
return [{json:{
  documentId: source.json.documentId,
  kbId: source.json.kbId,
  chunks: source.json.chunks,
  chunkCount: source.json.chunkCount,
  manifest: source.json.manifest
}}];

