parameters.jsCode:
const contract = $('Return Conversion').first().json;
const response = $input.first().json;
const chunks = contract.chunks;
const embeddings = response.embeddings;
if (!Array.isArray(chunks) || chunks.length === 0) throw new Error('No chunks supplied for indexing');
if (!Array.isArray(embeddings) || embeddings.length !== chunks.length) {
  throw new Error('Ollama embedding count does not match chunk count');
}
const points = chunks.map((chunk, index) => {
  const vector = embeddings[index];
  if (!Array.isArray(vector) || vector.length !== 768) {
    throw new Error('Embedding dimension must be 768 for chunk ' + index);
  }
  return {
    id: chunk.id,
    vector,
    payload: {
      document_id: chunk.document_id,
      kb_id: chunk.kb_id,
      chunk_id: chunk.chunk_id,
      chunk_index: chunk.chunk_index,
      text: chunk.text,
      heading_path: chunk.heading_path || [],
      page_start: chunk.page_start,
      page_end: chunk.page_end,
      content_type: chunk.content_type,
      source_key: chunk.source_key,
      source_sha256: chunk.source_sha256,
      filename: chunk.filename
    }
  };
});
return [{json:{documentId:contract.documentId,kbId:contract.kbId,chunkCount:chunks.length,points}}];

