UPDATE rag_documents SET status = 'indexed', chunk_count = $2::integer, indexed_at = now(), error_code = NULL, error_message = NULL, error_details = NULL, updated_at = now() WHERE id = $1::uuid;
INSERT INTO rag_document_events(document_id, status, stage, details) VALUES ($1::uuid, 'indexed', 'qdrant', jsonb_build_object('chunkCount', $2::integer, 'collection', 'rag_chunks'));
SELECT $1::text AS "documentId", $2::integer AS "chunkCount", 'indexed'::text AS status;

parameters.jsCode:
const d = $input.first().json;
return [{json:{
  ok: true,
  action: 'ingest',
  documentId: d.documentId,
  kbId: d.kbId || null,
  status: d.status,
  chunkCount: Number(d.chunkCount || 0),
  skipped: Boolean(d.skipped),
  requestSource: d.requestSource || 'internal'
}}];

const d = $input.first().json;
return [{json:{
  ok: false,
  action: 'ingest',
  documentId: d.documentId || null,
  status: d.status || 'failed',
  error: { stage: d.errorStage || d.stage || 'ingestion', code: d.errorCode || 'INGESTION_FAILED', message: d.errorMessage || d.message || d.error?.message || 'Ingestion failed' },
  requestSource: d.requestSource || 'internal'
}}];

const response = $input.first().json;
const request = $('Normalize and Validate Request').first().json;
const points = Array.isArray(response?.result?.points) ? response.result.points : (Array.isArray(response?.result) ? response.result : []);
const sources = points.map((point, index) => {
  const p = point.payload || {};
  return {
    id: 'S' + (index + 1),
    score: Number(point.score || 0),
    documentId: p.document_id || null,
    chunkId: p.chunk_id || null,
    filename: p.filename || 'unknown',
    pageStart: p.page_start ?? null,
    pageEnd: p.page_end ?? null,
    headingPath: Array.isArray(p.heading_path) ? p.heading_path : [],
    sourceKey: p.source_key || null,
    text: String(p.text || '')
  };
});
const context = sources.length
  ? sources.map(s => '[' + s.id + '] ' + s.filename + (s.pageStart != null ? ' page ' + s.pageStart : '') + '\n' + s.text).join('\n\n')
  : '(No matching context was retrieved.)';
const system = [
  'You are a local retrieval-grounded assistant.',
  'Answer only from the supplied context.',
  'Cite factual claims using the provided source IDs such as [S1].',
  'If the context is insufficient, say that the indexed documents do not contain enough information.',
  'Do not invent sources, filenames, page numbers, or facts.',
  'Keep the answer concise and useful.'
].join(' ');
return [{json:{query:request.query,kbId:request.kbId,model:'qwen3:4b',sources,context,system}}];

const response = $input.first().json;
const context = $('Assemble Grounded Context').first().json;
const rawAnswer = String(response?.message?.content || response?.response || '').trim();\nconst answer = rawAnswer.includes('</think>') ? rawAnswer.split('</think>').pop().trim() : rawAnswer;
return [{json:{
  ok: true,
  action: 'query',
  query: context.query,
  answer: answer || 'The local model returned an empty answer.',
  sources: context.sources.map(({text, ...source}) => source),
  retrieval: { type: 'vector', resultCount: context.sources.length, collection: 'rag_chunks' },
  model: context.model
}}];

const merged=$input.first();
let source=null;
try { source=$('Normalize and Validate Request').first(); } catch {}
if (!source?.binary?.data) {
  try { source=$('Prepare Watched File').first(); } catch {}
}
if (!source?.binary?.data) throw new Error('Intake source binary is unavailable');
return [{json:merged.json,binary:source.binary}];
